/**
 * Card-level classes generated by block color/border supports.
 *
 * @param {string} className Class list from useBlockProps.
 * @return {string} Filtered class list safe for the outer list wrapper.
 */
export function stripCardClassesFromWrapper( className = '' ) {
	return className
		.split( /\s+/ )
		.filter( ( cls ) => {
			if ( ! cls ) {
				return false;
			}

			if (
				cls === 'has-background' ||
				cls === 'has-text-color' ||
				cls === 'has-link-color' ||
				cls === 'has-border-color'
			) {
				return false;
			}

			return ! /^has-[\w-]+-(?:color|background-color|border-color|gradient-background)$/.test(
				cls
			);
		} )
		.join( ' ' );
}

/**
 * Card-level inline styles that belong on each job card, not the list wrapper.
 *
 * @param {Object} style Inline style object from useBlockProps.
 * @return {Object} Wrapper-safe inline styles (layout spacing only).
 */
export function stripCardStylesFromWrapper( style = {} ) {
	if ( ! style || typeof style !== 'object' ) {
		return {};
	}

	const wrapperStyle = { ...style };

	const cardStyleKeys = [
		'background',
		'backgroundColor',
		'color',
		'border',
		'borderColor',
		'borderStyle',
		'borderWidth',
		'borderRadius',
		'borderTop',
		'borderRight',
		'borderBottom',
		'borderLeft',
		'padding',
		'paddingTop',
		'paddingRight',
		'paddingBottom',
		'paddingLeft',
	];

	cardStyleKeys.forEach( ( key ) => {
		delete wrapperStyle[ key ];
	} );

	return wrapperStyle;
}
